import { createProgramAction, createTargetAction, markNotificationReadAction } from "@/app/actions";
import { EmptyState, StatusBadge } from "@/components/shared";
import type { getMasterData, getSettingsData } from "@/lib/data";
import { Bell, Plus, Target } from "lucide-react";

type SettingsData = Awaited<ReturnType<typeof getSettingsData>>;
type MasterData = Awaited<ReturnType<typeof getMasterData>>;
const inputClass = "w-full rounded-xl border border-slate-200 bg-white px-3 py-2.5 text-sm text-slate-800 outline-none focus:border-emerald-500 focus:ring-4 focus:ring-emerald-500/10";

export function SettingsManager({ data, master, isManager }: { data: SettingsData; master: MasterData | null; isManager: boolean }) {
  return <div className="grid gap-5 xl:grid-cols-[1fr_1fr]"><section className="rounded-2xl border border-slate-200 bg-white shadow-sm"><header className="border-b border-slate-100 px-5 py-4"><h2 className="font-display text-lg font-bold text-slate-900">Notifikasi aplikasi</h2><p className="mt-1 text-xs text-slate-500">Pengingat dan informasi yang ditujukan kepada Anda.</p></header><div className="divide-y divide-slate-100">{data.notifications.length ? data.notifications.map((item) => <div key={item.id} className={`px-5 py-4 ${!item.isRead ? "bg-emerald-50/40" : ""}`}><div className="flex gap-3"><span className="mt-0.5 grid size-8 shrink-0 place-items-center rounded-lg bg-emerald-100 text-emerald-700"><Bell size={16}/></span><div className="min-w-0 flex-1"><div className="flex items-center justify-between gap-2"><p className="text-sm font-bold text-slate-800">{item.title}</p>{!item.isRead && <span className="size-2 rounded-full bg-emerald-500"/>}</div><p className="mt-1 text-xs leading-5 text-slate-500">{item.message}</p>{!item.isRead && <form action={markNotificationReadAction} className="mt-2"><input type="hidden" name="id" value={item.id}/><button className="text-[11px] font-bold text-emerald-700 hover:text-emerald-900">Tandai sudah dibaca</button></form>}</div></div></div>) : <EmptyState title="Belum ada notifikasi" description="Pengingat muraja'ah dan informasi pondok akan muncul di sini."/>}</div></section><section className="rounded-2xl border border-slate-200 bg-white shadow-sm"><header className="border-b border-slate-100 px-5 py-4"><h2 className="font-display text-lg font-bold text-slate-900">Program hafalan</h2><p className="mt-1 text-xs text-slate-500">Program yang tersedia pada input dan target pembinaan.</p></header><div className="divide-y divide-slate-100">{data.programs.map((program) => <div key={program.id} className="flex items-center justify-between gap-3 px-5 py-3.5"><div><p className="text-sm font-bold text-slate-800">{program.name}</p><p className="mt-0.5 text-xs text-slate-500">{program.description ?? "Tanpa deskripsi"} · satuan {program.unit}</p></div><span className="rounded-full bg-slate-100 px-2 py-1 text-[10px] font-bold text-slate-600">{program.type}</span></div>)}</div></section>{isManager && master && <><form action={createProgramAction} className="rounded-2xl border border-emerald-100 bg-emerald-50/50 p-5 shadow-sm"><div className="flex items-center gap-2"><span className="grid size-9 place-items-center rounded-xl bg-emerald-900 text-white"><Plus size={18}/></span><div><h2 className="font-display text-lg font-bold">Tambah Program</h2><p className="text-xs text-slate-500">Tahfidz, hadits, matan, nazham, atau kitab.</p></div></div><div className="mt-5 grid gap-3 sm:grid-cols-2"><label><span className="mb-1.5 block text-xs font-bold text-slate-600">Nama program</span><input className={inputClass} name="name" placeholder="Contoh: Matan Jurumiyah" required/></label><label><span className="mb-1.5 block text-xs font-bold text-slate-600">Jenis</span><select className={inputClass} name="type" defaultValue="quran"><option value="quran">Al-Qur'an</option><option value="murajaah">Muraja'ah</option><option value="hadits">Hadits</option><option value="matan">Matan</option><option value="nazham">Nazham</option><option value="kitab">Kitab</option></select></label><label><span className="mb-1.5 block text-xs font-bold text-slate-600">Satuan target</span><input className={inputClass} name="unit" placeholder="ayat / bait / halaman" required/></label><label><span className="mb-1.5 block text-xs font-bold text-slate-600">Deskripsi singkat</span><input className={inputClass} name="description" placeholder="Keterangan program"/></label></div><button className="mt-4 rounded-xl bg-emerald-900 px-4 py-2.5 text-sm font-bold text-white hover:bg-emerald-800">Simpan Program</button></form><form action={createTargetAction} className="rounded-2xl border border-amber-100 bg-amber-50/50 p-5 shadow-sm"><div className="flex items-center gap-2"><span className="grid size-9 place-items-center rounded-xl bg-amber-500 text-white"><Target size={18}/></span><div><h2 className="font-display text-lg font-bold">Tetapkan Target</h2><p className="text-xs text-slate-500">Tetapkan pada santri atau halaqah tertentu.</p></div></div><div className="mt-5 grid gap-3 sm:grid-cols-2"><label><span className="mb-1.5 block text-xs font-bold text-slate-600">Program</span><select className={inputClass} name="programId" required defaultValue=""><option value="">Pilih program</option>{data.programs.map((item) => <option key={item.id} value={item.id}>{item.name}</option>)}</select></label><label><span className="mb-1.5 block text-xs font-bold text-slate-600">Santri (opsional)</span><select className={inputClass} name="studentId" defaultValue=""><option value="">Pilih santri</option>{master.students.map((item) => <option key={item.id} value={item.id}>{item.name}</option>)}</select></label><label><span className="mb-1.5 block text-xs font-bold text-slate-600">Halaqah (opsional)</span><select className={inputClass} name="halaqahId" defaultValue=""><option value="">Pilih halaqah</option>{master.halaqahs.map((item) => <option key={item.id} value={item.id}>{item.name}</option>)}</select></label><label><span className="mb-1.5 block text-xs font-bold text-slate-600">Target harian</span><input className={inputClass} name="dailyTarget" type="number" min="0" defaultValue="0" required/></label><label><span className="mb-1.5 block text-xs font-bold text-slate-600">Target mingguan</span><input className={inputClass} name="weeklyTarget" type="number" min="0" defaultValue="0" required/></label><label><span className="mb-1.5 block text-xs font-bold text-slate-600">Target bulanan</span><input className={inputClass} name="monthlyTarget" type="number" min="0" defaultValue="0" required/></label></div><label className="mt-3 block"><span className="mb-1.5 block text-xs font-bold text-slate-600">Catatan target</span><input className={inputClass} name="notes" placeholder="Contoh: fokus kelancaran dan konsistensi"/></label><button className="mt-4 rounded-xl bg-amber-500 px-4 py-2.5 text-sm font-bold text-white hover:bg-amber-600">Simpan Target</button></form></>}</div>;
}
